<template><section class="page"><van-nav-bar title="账户" left-arrow @click-left="router.back()"/><div v-if="loading" class="state-card"><van-loading/></div><van-empty v-else-if="error" image="error" :description="error"><van-button @click="load">重试</van-button></van-empty><van-empty v-else-if="!flat.length" description="暂无账户"/><van-cell-group v-else inset><van-cell v-for="account in flat" :key="account.name" :title="account.name" :label="account.currencies.join('、')" is-link :to="`/accounts/${encodeURIComponent(account.name)}`"/></van-cell-group></section></template>
<script setup lang="ts">
import { computed,onMounted,ref } from 'vue';import { useRouter } from 'vue-router';import { accountsApi,type Account } from '../../api/accounts';import type { ApiError } from '../../api/client'
const router=useRouter();const accounts=ref<Account[]>([]);const loading=ref(false);const error=ref('');const flatten=(items:Account[]):Account[]=>items.flatMap(item=>[item,...flatten(item.children||[])]);const flat=computed(()=>flatten(accounts.value));async function load(){loading.value=true;error.value='';try{accounts.value=await accountsApi.getAccounts()}catch(reason){error.value=(reason as ApiError).message}finally{loading.value=false}}onMounted(load)
</script>
